<?php require_once __DIR__.'/../config/database.php'; require_once __DIR__.'/../includes/functions.php'; require_login(); $where=[];$p=[]; if((current_user()['role_name']??'')!=='admin'){ $where[]='c.user_id=?'; $p[]=current_user()['id']; } foreach(['status'=>'d.diagnosis','location'=>'c.location'] as $k=>$col){ if(!empty($_GET[$k])){ $where[]="$col LIKE ?"; $p[]='%'.$_GET[$k].'%'; }} if(!empty($_GET['date'])){ $where[]='DATE(c.created_at)=?'; $p[]=$_GET['date']; } $sql='SELECT c.*,u.name,d.diagnosis,r.code rule_code FROM consultations c JOIN users u ON u.id=c.user_id JOIN diagnosis_results d ON d.consultation_id=c.id LEFT JOIN rules r ON r.id=d.rule_id'.($where?' WHERE '.implode(' AND ',$where):'').' ORDER BY c.created_at DESC'; $stmt=$pdo->prepare($sql); $stmt->execute($p); $rows=$stmt->fetchAll(); if(isset($_GET['export'])){ header('Content-Type:text/csv'); header('Content-Disposition:attachment; filename=laporan.csv'); echo "Tanggal,Lokasi,User,Status,Rule\n"; foreach($rows as $r) echo "{$r['created_at']},{$r['location']},{$r['name']},{$r['diagnosis']},{$r['rule_code']}\n"; exit; } require_once __DIR__.'/../includes/header.php'; ?><div class="container"><h2>Laporan Riwayat Konsultasi</h2><form class="card p-3 mb-3"><div class="row g-2"><div class="col"><input type="date" name="date" class="form-control"></div><div class="col"><input name="location" class="form-control" placeholder="Lokasi"></div><div class="col"><select name="status" class="form-select"><option value="">Semua Status</option><option>Rendah</option><option>Sedang</option><option>Tinggi</option><option>Sangat Tinggi</option></select></div><div class="col"><button class="btn btn-primary">Filter</button> <button name="export" value="csv" class="btn btn-success">Excel/CSV</button> <button type="button" class="btn btn-secondary" data-print>Print/PDF</button></div></div></form><table class="table"><tr><th>Tanggal</th><th>Lokasi</th><th>User</th><th>Status</th><th>Rule</th><th>Detail</th></tr><?php foreach($rows as $r): ?><tr><td><?=$r['created_at']?></td><td><?=e($r['location'])?></td><td><?=e($r['name'])?></td><td><?=e($r['diagnosis'])?></td><td><?=e($r['rule_code'])?></td><td><a href="../hasil/index.php?id=<?=$r['id']?>">Lihat</a></td></tr><?php endforeach; ?></table></div><?php require_once __DIR__.'/../includes/footer.php'; ?>
